"use client"

import { type VariantProps } from "class-variance-authority"
import { LikeButtonUI, likeButtonVariants } from "./ui"
import {
  useLike,
  type LikeResult,
  type UseLikeReturn,
  type UseLikeOptions,
} from "./use-like"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { LikeButtonUI, likeButtonVariants, type LikeButtonUIProps } from "./ui"
export {
  useLike,
  type LikeResult,
  type UseLikeReturn,
  type UseLikeOptions,
} from "./use-like"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface LikeButtonProps
  extends VariantProps<typeof likeButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** Transaction ID of the content to like */
  txid: string
  /** Current like count to display */
  count?: number
  /** Whether the current user has already liked this content */
  liked?: boolean
  /** Called to broadcast a like action */
  onLike: (txid: string) => Promise<LikeResult>
  /** Called to broadcast an unlike action */
  onUnlike?: (txid: string) => Promise<LikeResult>
  /** Called after a successful like/unlike */
  onToggled?: (liked: boolean, result: LikeResult) => void
  /** Called on error */
  onError?: (error: Error) => void
  /** Disable the button */
  disabled?: boolean
  /** Use thumbs-up icon instead of heart */
  useThumbsUp?: boolean
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * An on-chain like/unlike toggle button for BSocial content.
 *
 * Delegates the actual transaction building and broadcasting to `onLike`
 * and `onUnlike` callbacks. Manages optimistic UI updates internally.
 *
 * @example
 * ```tsx
 * import { LikeButton } from "@/components/blocks/like-button"
 *
 * <LikeButton
 *   txid="abc123..."
 *   count={42}
 *   liked={false}
 *   onLike={async (txid) => {
 *     // build BSocial like tx and broadcast
 *     return { txid: "def456..." }
 *   }}
 * />
 * ```
 */
export function LikeButton({
  variant = "default",
  className,
  txid,
  count = 0,
  liked = false,
  onLike,
  onUnlike,
  onToggled,
  onError,
  disabled = false,
  useThumbsUp = false,
}: LikeButtonProps) {
  const hook = useLike({
    txid,
    count,
    liked,
    onLike,
    onUnlike,
    onToggled,
    onError,
  })

  return (
    <LikeButtonUI
      variant={variant}
      className={className}
      isLiked={hook.isLiked}
      displayCount={hook.displayCount}
      isLoading={hook.isLoading}
      onToggle={hook.handleToggle}
      disabled={disabled}
      useThumbsUp={useThumbsUp}
    />
  )
}

"use client"

import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Heart, Loader2, ThumbsUp } from "lucide-react"

// ---------------------------------------------------------------------------
// Variant definitions
// ---------------------------------------------------------------------------

export const likeButtonVariants = cva(
  "inline-flex items-center gap-1.5 font-medium transition-all select-none",
  {
    variants: {
      variant: {
        default:
          "rounded-md border border-input bg-background px-3 py-1.5 text-sm shadow-sm hover:bg-accent hover:text-accent-foreground",
        compact:
          "rounded-full border border-input bg-background size-8 justify-center text-sm shadow-sm hover:bg-accent hover:text-accent-foreground p-0",
        text: "text-sm text-muted-foreground hover:text-foreground bg-transparent px-1 py-0.5",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
)

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface LikeButtonUIProps
  extends VariantProps<typeof likeButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** Whether the content is currently liked */
  isLiked: boolean
  /** Current display count */
  displayCount: number
  /** Whether a like/unlike action is in progress */
  isLoading: boolean
  /** Toggle the like state */
  onToggle: () => void
  /** Disable the button */
  disabled?: boolean
  /** Use thumbs-up icon instead of heart */
  useThumbsUp?: boolean
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function LikeButtonUI({
  variant = "default",
  className,
  isLiked,
  displayCount,
  isLoading,
  onToggle,
  disabled = false,
  useThumbsUp = false,
}: LikeButtonUIProps) {
  const isCompact = variant === "compact"
  const IconComponent = useThumbsUp ? ThumbsUp : Heart

  return (
    <Button
      variant="ghost"
      size="sm"
      className={cn(
        likeButtonVariants({ variant }),
        isLiked && "text-primary border-primary/30 bg-primary/5",
        isLiked && variant === "text" && "bg-transparent text-primary",
        className,
      )}
      onClick={onToggle}
      disabled={disabled || isLoading}
      aria-label={isLiked ? "Unlike" : "Like"}
      aria-pressed={isLiked}
    >
      {isLoading ? (
        <Loader2
          className={cn("animate-spin", isLiked && "fill-current")}
          data-icon="inline-start"
          aria-hidden="true"
        />
      ) : (
        <IconComponent
          className={cn(
            "transition-transform",
            isLiked && "fill-current scale-110",
            !isLiked && "hover:scale-110",
          )}
          data-icon="inline-start"
          aria-hidden="true"
        />
      )}
      {!isCompact && displayCount > 0 && (
        <Badge variant="secondary" className="h-5 min-w-5 justify-center px-1.5 text-xs tabular-nums">
          {displayCount}
        </Badge>
      )}
    </Button>
  )
}

import { useCallback, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface LikeResult {
  /** Transaction ID of the like/unlike action */
  txid?: string
  /** Raw transaction hex */
  rawtx?: string
  /** Error message if the action failed */
  error?: string
}

export interface UseLikeOptions {
  /** Transaction ID of the content to like */
  txid: string
  /** Current like count to display */
  count?: number
  /** Whether the current user has already liked this content */
  liked?: boolean
  /** Called to broadcast a like action */
  onLike: (txid: string) => Promise<LikeResult>
  /** Called to broadcast an unlike action */
  onUnlike?: (txid: string) => Promise<LikeResult>
  /** Called after a successful like/unlike */
  onToggled?: (liked: boolean, result: LikeResult) => void
  /** Called on error */
  onError?: (error: Error) => void
}

export interface UseLikeReturn {
  /** Whether the content is currently liked */
  isLiked: boolean
  /** Current display count */
  displayCount: number
  /** Whether a like/unlike action is in progress */
  isLoading: boolean
  /** Toggle the like state */
  handleToggle: () => Promise<void>
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useLike({
  txid,
  count = 0,
  liked = false,
  onLike,
  onUnlike,
  onToggled,
  onError,
}: UseLikeOptions): UseLikeReturn {
  const [isLiked, setIsLiked] = useState(liked)
  const [displayCount, setDisplayCount] = useState(count)
  const [isLoading, setIsLoading] = useState(false)

  const handleToggle = useCallback(async () => {
    if (isLoading) return

    const wasLiked = isLiked

    // Optimistic update
    setIsLiked(!wasLiked)
    setDisplayCount((prev) => (wasLiked ? Math.max(0, prev - 1) : prev + 1))
    setIsLoading(true)

    try {
      let result: LikeResult

      if (wasLiked && onUnlike) {
        result = await onUnlike(txid)
      } else if (wasLiked) {
        // No unlike handler, revert optimistic update
        setIsLiked(true)
        setDisplayCount((prev) => prev + 1)
        setIsLoading(false)
        return
      } else {
        result = await onLike(txid)
      }

      if (result.error) {
        // Revert optimistic update
        setIsLiked(wasLiked)
        setDisplayCount((prev) => (wasLiked ? prev + 1 : Math.max(0, prev - 1)))
        onError?.(new Error(result.error))
      } else {
        onToggled?.(!wasLiked, result)
      }
    } catch (err) {
      // Revert optimistic update
      setIsLiked(wasLiked)
      setDisplayCount((prev) => (wasLiked ? prev + 1 : Math.max(0, prev - 1)))
      const error = err instanceof Error ? err : new Error("Failed to toggle like")
      onError?.(error)
    } finally {
      setIsLoading(false)
    }
  }, [isLoading, isLiked, txid, onLike, onUnlike, onToggled, onError])

  return {
    isLiked,
    displayCount,
    isLoading,
    handleToggle,
  }
}
